"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[14945],{57368:e=>{e.exports=JSON.parse('{"tag":{"label":"tool","permalink":"/dst-api-webdocs/docs/tags/tool","allTagsPath":"/dst-api-webdocs/docs/tags","count":25,"items":[{"id":"game-scripts/prefabs/axe","title":"Axe","description":"Provides a multiplayer-synced chopping tool with durability, weapon damage, and skin-aware equip animations for characters.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/axe"},{"id":"game-scripts/prefabs/axe_pickaxe","title":"Axe Pickaxe","description":"A multitool item that functions as both an axe and a pickaxe, with limited durability and weapon capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/axe_pickaxe"},{"id":"game-scripts/prefabs/bugnet","title":"Bugnet","description":"A reusable tool-and-weapon item that captures insects and degrades after a fixed number of uses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bugnet"},{"id":"game-scripts/prefabs/cane","title":"Cane","description":"A wearable weapon tool that modifies the owner\'s movement speed and deals damage when used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cane"},{"id":"game-scripts/prefabs/compass","title":"Compass","description":"A consumable item that reveals map terrain and depletes over time when equipped, while also functioning as a basic melee weapon.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/compass"},{"id":"game-scripts/prefabs/farm_hoe","title":"Farm Hoe","description":"A tool prefab that enables tilling soil, dealing damage, and providing floating buoyancy; its durability is managed by finite uses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farm_hoe"},{"id":"game-scripts/prefabs/fence_rotator","title":"Fence Rotator","description":"A consumable tool used to rotate fences; equipped as an inventory item and decrements finite uses per rotation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fence_rotator"},{"id":"game-scripts/prefabs/hammer","title":"Hammer","description":"A durable tool and weapon used for destroying structures and enemies; has finite durability and triggers skin overrides when equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hammer"},{"id":"game-scripts/prefabs/hermitcrab_shell","title":"Hermitcrab Shell","description":"A consumable horn item that enables teleportation to the Hermit\'s house and has a secondary use for tending plants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrab_shell"},{"id":"game-scripts/prefabs/horn","title":"Horn","description":"A consumable instrument that\u53ec\u96c6s beefalo followers and tends farm plants when used by the player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/horn"},{"id":"game-scripts/prefabs/houndwhistle","title":"Houndwhistle","description":"A consumable tool that emits a whistle sound to attract hounds and wargs, adding them as followers to the user.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/houndwhistle"},{"id":"game-scripts/components/magician","title":"Magician","description":"Manages the state and lifecycle of a magician tool currently being used by an entity, including equipping, holding, and dropping behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/magician"},{"id":"game-scripts/prefabs/merm_tool","title":"Merm Tool","description":"Implements a reusable, tool-based weapon for Merm NPCs with damage modified by combat state and finite durability for chopping, mining, digging, and tilling actions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/merm_tool"},{"id":"game-scripts/prefabs/panflute","title":"Panflute","description":"A musical instrument that induces sleep, grogginess, or other effects in nearby entities and can summon Wortox souls when played.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/panflute"},{"id":"game-scripts/prefabs/pickaxe","title":"Pickaxe","description":"A tool-and-weapon prefab providing mining and combat functionality with finite durability, equipped with visual, inventory, and network support.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pickaxe"},{"id":"game-scripts/prefabs/pickaxe_lunarplant","title":"Pickaxe Lunarplant","description":"A specialized mining tool that gains increased damage when equipped alongside the Lunar Plant Hat, with separate states for intact and broken conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pickaxe_lunarplant"},{"id":"game-scripts/prefabs/pitchfork","title":"Pitchfork","description":"A throwable tool prefab that enables terrain modification and combat, with limited durability and skin support.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pitchfork"},{"id":"game-scripts/prefabs/quagmire_hoe","title":"Quagmire Hoe","description":"A tool prefab used in Quagmire game mode to interact with soil and terrain, featuring dedicated animation and network state management.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_hoe"},{"id":"game-scripts/prefabs/rabbitkinghorn","title":"Rabbitkinghorn","description":"A consumable musical instrument that summons a rabbit king chest when used; tracks usage and validates spawn locations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbitkinghorn"},{"id":"game-scripts/prefabs/razor","title":"Razor","description":"A server-side prefab component that provides razor functionality as a combat/shaving tool.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/razor"},{"id":"game-scripts/prefabs/shovel","title":"Shovel","description":"Implements the shovel and golden shovel prefabs with dig capability, limited durability, weapon damage, and equip/unequip animation handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shovel"},{"id":"game-scripts/prefabs/shovel_lunarplant","title":"Shovel Lunarplant","description":"A lunar plant\u2013themed shovel that grants bonus damage and planar damage when equipped alongside a Lunar Plant Hat, with dynamic behavior based on breakage state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shovel_lunarplant"},{"id":"game-scripts/prefabs/slingshotmodkit","title":"Slingshotmodkit","description":"A consumable item that allows the player to open the Slingshot Modding interface for compatible slingshots.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshotmodkit"},{"id":"game-scripts/prefabs/trident","title":"Trident","description":"A magical trident that enables\u8fdc\u7a0b wave-spawned explosions on water and interacts with fish, plants, and structures in the ocean.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trident"},{"id":"game-scripts/prefabs/wateringcan","title":"Wateringcan","description":"A tool prefab that holds water for plant care, providing wetness, cooling, and protection effects when used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wateringcan"}],"unlisted":false}}')}}]);